mapper.select:
select CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' else ACCT_CLASS end as ACCT_CLASS, a.dept, b.dept_name, a.acct, a.EXPEN_SEL, a.EXPEN_SEL명, a.SUB_NAME, a.ITEM_NAME, sum(a.ACCT_AMT) ACCT_AMT from doi_acct_expen a left join doi_dept b on (a.yyyymm=b.yyyymm and b.sel_code=a.sel_code and b.site=a.site and b.dept=a.dept) where 1=1 and a.EXPEN_SEL not in ('MDAX','MIAX') and a.EXPEN_SEL != 'NONE' --미분류 제외
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and a.ACCT_CLASS = #{costGubun}
AND a.ACCT_CLASS='AA' AND a.EXPEN_SEL NOT LIKE 'M%'
AND a.ACCT_CLASS='AA' AND a.EXPEN_SEL LIKE 'X%'
group by CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' else ACCT_CLASS end , a.dept, b.dept_name, a.acct, a.EXPEN_SEL, a.EXPEN_SEL명, a.SUB_NAME, a.ITEM_NAME
union all select '재료비', '000', '제조공통', CASE WHEN MAT_CLASS='원자재' then '51001010' else '51002010' end, CASE WHEN MAT_CLASS='원자재' then 'MDAX' else 'MIDX' end, CASE WHEN MAT_CLASS='원자재' then '직접재료비' else '간접재료비' end, '재료비', CASE WHEN MAT_CLASS='원자재' then '원재료비' else '부재료비' end, sum(IN_AMT) 금액 from doi_material_resc where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by MAT_CLASS HAVING sum(IN_AMT) > 0
order BY 1,2,3,4,5;

select CASE WHEN ACCT_CLASS='AA' THEN '제조비용' WHEN ACCT_CLASS='BB' THEN '개발비' WHEN ACCT_CLASS='CC' THEN '판매관리비' END ACCT_CLASS, EXPEN_SEL, EXPEN_SEL명, SUB_NAME, ITEM_NAME, SUM(ACCT_AMT) ACCT_AMT from DOI_ACCT_EXPEN where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and expen_sel not in ('MDAX','MIAX') --재료비 제외 GROUP BY YYYYMM,SEL_CODE,SITE,SUB_NAME,ITEM_NAME,EXPEN_SEL,EXPEN_SEL명,ACCT_CLASS UNION ALL select '제조비용', CASE WHEN MAT_CLASS='원자재' then 'MDAX' else 'MIAX' end, CASE WHEN MAT_CLASS='원자재' then '직접재료비' else '간접재료비' end, '재료비', CASE WHEN MAT_CLASS='원자재' then '원재료비' else '부재료비' end, sum(IN_AMT) 금액 --select * from doi_material_resc where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by CASE WHEN MAT_CLASS='원자재' then 'MDAX' else 'MIAX' end, CASE WHEN MAT_CLASS='원자재' then '직접재료비' else '간접재료비' end, CASE WHEN MAT_CLASS='원자재' then '원재료비' else '부재료비' end HAVING sum(IN_AMT) > 0 order by ACCT_CLASS,EXPEN_SEL,SUB_NAME,ITEM_NAME;

select.if:
select CASE WHEN a.ACCT_CLASS='AA' then '가공비' WHEN a.ACCT_CLASS='CC' then '판매관리비' WHEN a.ACCT_CLASS='BB' then '개발비' else a.ACCT_CLASS end as ACCT_CLASS , b.DEPT_NAME, EXPEN_SEL, EXPEN_SEL명, SUB_NAME, ITEM_NAME, SUM(ACCT_AMT) ACCT_AMT from DOI_ACCT_EXPEN a inner join doi_dept b on(a.dept=b.dept) where 1=1
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and a.EXPEN_SEL = #{expenSel}
group by a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.SITE end, CASE WHEN a.ACCT_CLASS='AA' then '가공비' WHEN a.ACCT_CLASS='CC' then '판매관리비' WHEN a.ACCT_CLASS='BB' then '개발비' else a.ACCT_CLASS end, b.DEPT_NAME,SUB_NAME,ITEM_NAME,EXPEN_SEL,EXPEN_SEL명 order by EXPEN_SEL;

select '제조경비' ACCT_CLASS, '제조공통' DEPT_NAME, CASE WHEN MAT_CLASS='원자재' then 'MDAX' else 'MIAX' end EXPEN_SEL, CASE WHEN MAT_CLASS='원자재' then '직접재료비' else '간접재료비' end EXPEN_SEL명, '재료비' SUB_NAME, CASE WHEN MAT_CLASS='원자재' then '원재료비' else '부재료비' end ITEM_NAME, --sum(in_qty) in_qty, sum(in_amt) acct_amt from DOI_MATERIAL_RESC a where 1 = 1
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and CASE WHEN MAT_CLASS='원자재' then 'MDAX' else 'MIAX' end = #{expenSel}
group by CASE WHEN MAT_CLASS='원자재' then 'MDAX' else 'MIAX' end, CASE WHEN MAT_CLASS='원자재' then '직접재료비' else '간접재료비' end, CASE WHEN MAT_CLASS='원자재' then '원재료비' else '부재료비' end

mapper.select:
select YYYYMM, SEL_CODE, DW_SITE as SITE, 구분, 도우모델 as MODEL, MODEL_N_TYPE, sum(BOH_MONTH) as BOH_MONTH, sum(IN_MONTH) as IN_MONTH, sum(BONUS_MONTH) as BONUS_MONTH, sum(EOH_MONTH) as EOH_MONTH, sum(OUT_MONTH) as OUT_MONTH, sum(LOSS_MONTH) as LOSS_MONTH, sum(NG_MONTH) as NG_MONTH, sum(수율제외_MONTH) as 수율제외_MONTH, sum(REWORK진행_MONTH) as REWORK진행_MONTH, sum(material_loss) as material_loss from DOI_PROD_SUBUL where 1=1
and YYYYMM = #{yyyymm}
and DW_SITE = #{site}
and 구분 = #{prodGubun}
group by YYYYMM,SEL_CODE,DW_SITE,구분,도우모델,MODEL_N_TYPE order by 1,2,3,model, MODEL_N_TYPE;

select lotrun_no,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,
수율제외_MONTH,REWORK진행_MONTH,material_loss
from DOI_PROD_LOTRUN
where 1=1

    and YYYYMM = #{yyyymm}


    and DW_SITE = #{site}


    and 구분 = #{prodGubun}


    and MODEL_N_TYPE = #{modelNType}

order by lotrun_no;

with base_cost as ( select model, '가공비' c_cost, avg(in_qty) in_qty, avg(in_qty + OUT_QTY + loss_qty)/ 2 as 환산수량, sum([in]) as 투입금액 from doi_cost where 1=1 and expen_sel not in ('MDAX','MIAX','NONE')
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by model union all select 도우모델 as model, case when mat_class='원자재' then '직접재료비' else '간접재료비' end, avg(in_qty) as in_qty, avg(환산량) as 환산수량, sum(배부금액) as 투입금액 from DOI_MAT_COST where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by 도우모델, case when mat_class='원자재' then '직접재료비' else '간접재료비' end ), in_cost as( select model, avg(in_qty) as in_qty, avg(환산수량) as chg_qty, sum(투입금액) as tot_amt, sum(case when c_cost='직접재료비' then 투입금액 else 0 end) d_matcost, sum(case when c_cost='간접재료비' then 투입금액 else 0 end) i_matcost, sum(case when c_cost='가공비' then 투입금액 else 0 end) fab_cost from base_cost group by model ) select model, in_qty, chg_qty, tot_amt, d_matcost, i_matcost, fab_cost, coalesce(d_matcost / nullif(in_qty, 0), 0)+ coalesce(i_matcost / nullif(chg_qty, 0), 0)+ coalesce(fab_cost / nullif(chg_qty, 0), 0) as sum_unitcost, coalesce(d_matcost / nullif(in_qty, 0), 0) dm_unitcost, coalesce(i_matcost / nullif(chg_qty, 0), 0) di_unitcost, coalesce(fab_cost / nullif(chg_qty, 0), 0) f_unitcost from in_cost order by model;

select 구분, MODEL, EXPEN_SEL, EXPEN_SEL명, in_qty, adj_qty, BOH, [IN] INPUT_AMT, SUB_NAME from doi_expen_matl where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and MODEL = #{model}
union all select '공통',도우모델, case when mat_class='원자재' then 'MDAX' else 'MIDX' end as expen_sel, case when mat_class='원자재' then '직접재료비' else '간접재료비' end as expen_sel명, in_qty, 환산량, 0, in_amt, mat_class from doi_mat_cost where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and 도우모델 = #{model}
order by 구분,EXPEN_SEL;

with BOM as ( select 자재번호,투입단위,자재대분류,row_number() over (partition by 자재번호 order by 자재명) as rn from doi_bom_mast WHERE 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and nullif(자재번호,'') is not null union all select 자재번호,투입단위,품목소분류 ,row_number() over (partition by 자재번호 order by 자재명) as rn from doi_cst_bom WHERE 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
) select --a.MAT_CLASS, CASE WHEN a.MAT_CLASS='원자재' THEN 'MDAX' ELSE 'MIAX' end as expen_sel, CASE WHEN a.MAT_CLASS='원자재' THEN '직접재료비' ELSE '간접재료비' end as expen_sel명, a.MAT_CODE, a.MAT_DESC, max(b.자재대분류) mat_lclass, max(b.투입단위) UNIT, SUM(a.IN_QTY) IN_QTY, AVG(a.UNIT_COST) UNIT_COST, SUM(a.IN_AMT) IN_AMT from DOI_MATERIAL_RESC a left join BOM b on (a.mat_code = b.자재번호 and b.rn=1) where 1=1 and a.sel_code = 'ACTUAL'
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
group by a.YYYYMM, a.SEL_CODE, a.SITE, a.MAT_CLASS, a.MAT_CODE, a.MAT_DESC having sum(in_amt) != 0 order by 5,1;

select YYYYMM, SEL_CODE, SITE, MAT_CODE, MAT_DESC, [SIZE], IN_QTY, UNIT_COST, IN_AMT, COST_GUBUN, MAT_CLASS, MODEL, MODEL_N_TYPE FROM DOI_MATERIAL_RESC where 1=1 and sel_code = 'ACTUAL'
and YYYYMM = #{yyyymm}
and SITE = #{site}
and mat_class = #{matClass}
order by 1,2,3,4;

WITH BOM as ( SELECT * FROM ( select b.yyyymm, b.자재번호, b.자재명, b.자재대분류, row_number() over (partition by b.자재번호 order by (b.자재대분류)) rn1 from doi_bom_mast b where 1=1 and yyyymm = #{yyyymm} and site = #{site} and nullif(자재번호, '') IS NOT NULL union all select c.yyyymm, c.자재번호, c.자재명, c.품목대분류, row_number() over (partition by c.자재번호 order by (c.품목대분류)) rn1 --select * from DOI_CST_BOM c where 1=1 and yyyymm = #{yyyymm} and site = #{site} and 품목자산분류 NOT IN ('카세트제품', '제품') and nullif(자재번호, '') IS NOT NULL
)a where rn1=1 ) select a.yyyymm, a.sel_code, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' end AS SITE, a.도우모델, a.자재번호, b.자재명, case when a.mat_class='원자재' then 'MDAX' else 'MIDX' end as expen_sel, case when a.mat_class='원자재' then '직접재료비' else '간접재료비' end as expen_sel명, a.mat_class, --a.자재대분류, a.in_amt, a.환산량, CASE WHEN 배부방식 IN ('BOM','CST') THEN a.소요량 ELSE NULL END AS 소요량, CASE WHEN 배부방식 = '공통' THEN a.소요량 ELSE NULL END AS 면적, a.사용량 as 배부적수, --소요량 * 환산량 a.배부율, a.배부금액, a.배부방식 from doi_mat_cost a left join bom b on (a.자재번호 = b.자재번호) where 1=1
and A.YYYYMM = #{yyyymm}
and A.SITE = #{site}
order by a.배부방식 desc,a.자재번호

select *
from doi_mat_cost
where 1=1

    and YYYYMM = #{yyyymm}


    and SITE = #{site}


    and mat_class = #{matClass}

order by 1,2,3,4,5,6;

select 도우모델, case when a.mat_class='원자재' then 'MDAX' else 'MIDX' end as expen_sel, case when a.mat_class='원자재' then '직접재료비' else '간접재료비' end as expen_sel명, --a.mat_class, sum(배부금액) 배부금액 from doi_mat_cost a where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
group by 도우모델, case when a.mat_class='원자재' then 'MDAX' else 'MIDX' end, case when a.mat_class='원자재' then '직접재료비' else '간접재료비' end order by 1,2;

select yyyymm, sel_code, site, 도우모델, 자재번호, mat_class, 자재대분류, in_amt, 환산량, 소요량, 배부율, 배부금액, 사용량, CASE WHEN 배부방식='공통' THEN '면적' ELSE 배부방식 END 배부방식 from doi_mat_cost where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and 도우모델 = #{model}
order by 1,2,3,4,5,6,7;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end SITE, 구분, MODEL, EXPEN_SEL, ACCT_NAME, SUB_NAME, ITEM_NAME, SUM(BOH) BOH, SUM([IN]) INPUT_AMT, SUM(EOH) EOH, SUM([OUT]) OUT_AMT, SUM(LOSS) LOSS from doi_cost where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and SUB_NAME LIKE '%' + #{acctName}
GROUP BY YYYYMM,SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end, 구분,MODEL,EXPEN_SEL,ACCT_NAME,SUB_NAME,ITEM_NAME order BY 1,2,3,4,5,6,7,8;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE ='VN' then 'VINA' else SITE end SITE, MODEL, STOCK, SUM(BOH) BOH, SUM([INPUT]) IN_QTY, SUM([OUT]) OUT_QTY, SUM(EOH) EOH from doi_stock where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
GROUP BY YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end, MODEL, STOCK ORDER BY 1,2,3,4

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end SITE, 구분, MODEL, EXPEN_SEL, EXPEN_SEL명, BOH AS BOH_QTY, BOH_AMT, INPUT AS IN_QTY, IN_AMT, EOH AS EOH_QTY, EOH_AMT, [OUT] AS OUT_QTY, OUT_AMT from doi_stco where 1=1 and sel_code = 'ACTUAL'
and YYYYMM = #{yyyymm}
and SITE = #{site}
and 구분 = #{gubun}
and BOH_AMT+IN_AMT+EOH_AMT+OUT_AMT > 0 order BY 1,2,3,4,5;

select 거래명세서번호, 거래명세서일, 부서, 담당자, 거래처, 품명, 품번, 판매단위, 수량, 통화, 환율, 판매단가, 판매금액, 부가세액, 판매금액계, 원화판매금액, 원화부가세액, 원화판매금액계, 매출수량, 매출금액계, 세금계산서금액계 from doi_sale_resc where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
union all select Invoice관리번호, Invoice_Date, 부서, 담당자, Buyer, 품명, 품번, 단위, 수량, 통화, 환율, 판매단가, 판매금액, null 부가세액, null 판매금액계, 원화판매금액, null 원화부가세액, null 원화판매금액계, null 매출수량, null 매출금액계, null 세금계산서금액계 from doi_invoice_resc where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
order by 거래처,거래명세서번호, 거래명세서일;

select YYYYMM, sel_code, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end AS SITE, 구분, model, 면적, 면적*adj_qty AS DIST_VALUE, dist_rate, SUB_NAME, ITEM_NAME, EXPEN_SEL, EXPEN_SEL명, adj_qty, in_qty, out_qty, loss_qty, unit_cost, [in] as input_Amt from doi_expen_matl where 1=1 and expen_sel != 'NONE'
and YYYYMM = #{yyyymm}
and SITE = #{site}
order by YYYYMM,SEL_CODE,SITE,MODEL,EXPEN_SEL;

select 구분,model,SUB_NAME,ITEM_NAME,EXPEN_SEL,EXPEN_SEL명,SALE_AMT,TOT_AMT,TOT_SMCE,TOT_ACCT,DIST_RATE,DIST_AMT
from DOI_SMCE_COST
where 1=1

    and YYYYMM = #{yyyymm}


    and SITE = #{site}

order by  model, EXPEN_SEL, EXPEN_SEL명 ,구분 ;  --SUB_NAME, ITEM_NAME,
